import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { ArrowLeft, User, FileText, MapPin, CreditCard, Mail, Phone, Calendar } from 'lucide-react';
import { Button } from '../../components/common/Button';
import { Card } from '../../components/common/Card';
import { DataTable } from '../../components/ui/DataTable';
import { DocumentViewer } from '../../components/common/DocumentViewer';
import { MediaViewer } from '../../components/common/MediaViewer';
import { getApplicantById, getApplicantApplications } from '../../services/applicant.service';
import toast from 'react-hot-toast';
import { PUBLIC_FILE_BASE_URL } from '../../config/appConfig';
import { formatDateIST, formatDateISTNoTime } from '../../utils/date';

const ApplicantView = () => {
    const { id } = useParams();
    const navigate = useNavigate();
    const [applicant, setApplicant] = useState(null);
    const [applications, setApplications] = useState([]);
    const [loading, setLoading] = useState(true);
    const [activeTab, setActiveTab] = useState('profile');

    useEffect(() => {
        const fetchData = async () => {
            setLoading(true);
            try {
                const [applicantRes, applicationsRes] = await Promise.all([
                    getApplicantById(id),
                    getApplicantApplications(id)
                ]);

                // Correctly extract data from API response structure
                setApplicant(applicantRes.data || applicantRes);
                setApplications(applicationsRes.data?.applications || applicationsRes.applications || []);
            } catch (error) {
                console.error('Failed to load applicant details', error);
                toast.error('Failed to load applicant details');
            } finally {
                setLoading(false);
            }
        };
        fetchData();
    }, [id, navigate]);

    if (loading) {
        return <div className="p-8 text-center">Loading applicant details...</div>;
    }

    if (!applicant) {
        return <div className="p-8 text-center">Applicant not found</div>;
    }

    const personal = applicant.personal || {};
    const address = applicant.addresses?.[0] || {};
    // Extract both current and permanent address details from the single address object if typical structure
    // Or check if addresses array has multiple entries. 
    // Based on API response: 
    // "addresses": [{ "address_line": "...", "district_name": "...", "permanent_address_same": true, ... }]

    const education = applicant.education || [];
    const experience = applicant.experience || [];
    const skills = applicant.skills || [];
    const documents = applicant.documents || [];

    // PAN temporarily disabled
    const corePersonalCodes = new Set(['PHOTO', 'SIGNATURE', 'AADHAAR', 'RESUME', 'DOMICILE']);
    const extraDocuments = documents.filter((d) => !corePersonalCodes.has(d?.doc_code));

    const InfoRow = ({ label, value }) => (
        <div className="flex flex-col sm:flex-row sm:justify-between py-2 border-b border-gray-100 last:border-0">
            <span className="text-sm text-slate-500 min-w-[150px]">{label}</span>
            <span className="text-sm font-medium text-slate-900">{value || '-'}</span>
        </div>
    );

    const Section = ({ title, icon: Icon, children }) => (
        <Card className="mb-6">
            <div className="flex items-center gap-2 mb-4 pb-2 border-b">
                {Icon && <Icon className="h-5 w-5 text-blue-600" />}
                <h3 className="text-lg font-semibold text-slate-800">{title}</h3>
            </div>
            <div className="space-y-1">
                {children}
            </div>
        </Card>
    );

    const getImageUrl = (filePath) => {
        if (!filePath) return '';
        const cleanPath = String(filePath).replace(/^\/+/, '');
        return `${PUBLIC_FILE_BASE_URL}/${cleanPath}`;
    };

    
    const applicationColumns = [
        { key: 'application_no', header: 'Application No' },
        { key: 'post_name', header: 'Post Applied', render: (_, row = {}) => row.post?.post_name || row.post_name || '-' },
        { key: 'post_code', header: 'Post Code', render: (_, row = {}) => row.post?.post_code || row.post_code || '-' },
        {
            key: 'status',
            header: 'Status',
            className: 'text-center',
            render: (_, row = {}) => (
                <span className={`inline-flex items-center rounded-full px-2 py-1 text-xs font-medium ${row.status === 'SELECTED' ? 'bg-green-100 text-green-700' :
                    row.status === 'ELIGIBLE' ? 'bg-blue-100 text-blue-700' : 'bg-gray-100 text-gray-800'
                    }`}>
                    {row.status?.replace(/_/g, ' ') || '-'}
                </span>
            )
        },
        {
            key: 'submitted_at',
            header: 'Submitted On',
            render: (_, row = {}) => formatDateIST(row.submitted_at, { includeTime: true })
        },
        {
            key: 'actions',
            header: 'Actions',
            className: 'text-center',
            render: (_value, row = {}) => (
                <div className="flex justify-center">
                    <Button
                        size="sm"
                        variant="ghost"
                        onClick={() => row.application_id && navigate(`/applications/${row.application_id}`)}
                        className="text-blue-600 hover:text-blue-900"
                    >
                        View
                    </Button>
                </div>
            )
        }
    ];

    return (
        <div className="space-y-6">
            <div className="flex items-center gap-4">
                <Button variant="ghost" onClick={() => navigate('/applicants')}>
                    <ArrowLeft className="h-5 w-5" />
                </Button>
                <div>
                    <h1 className="text-2xl font-bold text-slate-900">{personal.full_name || applicant.full_name}</h1>
                    <p className="text-sm text-slate-500">
                        Applicant No: {applicant.applicant_no} • Registered: {formatDateIST(applicant.created_at, { includeTime: true })}
                    </p>
                </div>
            </div>

            {/* Tabs */}
            <div className="border-b border-slate-200">
                <nav className="-mb-px flex space-x-8">
                    {['Profile', 'Education & Experience', 'Skills', 'Documents', 'Applications'].map((tab) => {
                        const tabKey = tab.toLowerCase().replace(/ & /g, '_').replace(/ /g, '_'); // simple slug
                        const isActive = activeTab === tabKey || (tabKey === 'profile' && activeTab === 'profile');
                        // mapping display name to key used in state
                        const dbKey = tab === 'Education & Experience' ? 'education_experience' : tab.toLowerCase();

                        return (
                            <button
                                key={dbKey}
                                onClick={() => setActiveTab(dbKey)}
                                className={`py-4 px-1 border-b-2 font-medium text-sm ${activeTab === dbKey
                                    ? 'border-blue-500 text-blue-600'
                                    : 'border-transparent text-slate-500 hover:text-slate-700 hover:border-slate-300'
                                    }`}
                            >
                                {tab === 'Applications' ? `Applications (${applications.length})` : tab === 'Skills' ? `Skills (${skills.length})` : tab}
                            </button>
                        );
                    })}
                </nav>
            </div>

            {activeTab === 'profile' && (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6 animate-in fade-in slide-in-from-bottom-2">
                    <div className="space-y-6">
                        <Section title="Personal Information" icon={User}>
                            <InfoRow label="Full Name" value={personal.full_name} />
                            {/* <InfoRow label="Father's Name" value={personal.father_name} /> */}
                            {/* <InfoRow label="Mother's Name" value={personal.mother_name} /> */}
                            <InfoRow label="Gender" value={personal.gender} />
                            <InfoRow label="Date of Birth" value={formatDateISTNoTime(personal.dob)} />
                            <InfoRow label="Marital Status" value={personal.marital_status} />
                            {/* <InfoRow label="Social Category" value={personal.social_category} /> // Not in API example but kept if needed */}
                            <InfoRow label="Aadhar Number" value={personal.aadhar_no} />
                            {/* PAN temporarily disabled */}
                            {/* <InfoRow label="PAN Number" value={personal.pan_no} /> */}
                            <InfoRow label="Domicile (Maharashtra)" value={personal.domicile_maharashtra === true ? 'Yes' : personal.domicile_maharashtra === false ? 'No' : '-'} />
                            <InfoRow label="Category" value={personal.category || personal.category_name} />
                            <div className="flex flex-col sm:flex-row sm:justify-between py-2 border-b border-gray-100 last:border-0">
                                <span className="text-sm text-slate-500 min-w-[150px]">Photo</span>
                                {personal.photo_path ? <MediaViewer src={personal.photo_path} fileName="Photo" variant="link" /> : '-'}
                            </div>
                            <div className="flex flex-col sm:flex-row sm:justify-between py-2 border-b border-gray-100 last:border-0">
                                <span className="text-sm text-slate-500 min-w-[150px]">Signature</span>
                                {personal.signature_path ? <MediaViewer src={personal.signature_path} fileName="Signature" variant="link" /> : '-'}
                            </div>
                            <div className="flex flex-col sm:flex-row sm:justify-between py-2 border-b border-gray-100 last:border-0">
                                <span className="text-sm text-slate-500 min-w-[150px]">Aadhaar File</span>
                                {personal.aadhaar_path ? <DocumentViewer src={personal.aadhaar_path} fileName="Aadhaar" variant="link" /> : '-'}
                            </div>
                            {/* PAN file temporarily disabled */}
                            {/* <div className="flex flex-col sm:flex-row sm:justify-between py-2 border-b border-gray-100 last:border-0">
                                <span className="text-sm text-slate-500 min-w-[150px]">PAN File</span>
                                {personal.pan_path ? <DocumentViewer src={personal.pan_path} fileName="PAN Card" variant="link" /> : '-'}
                            </div> */}
                            <div className="flex flex-col sm:flex-row sm:justify-between py-2 border-b border-gray-100 last:border-0">
                                <span className="text-sm text-slate-500 min-w-[150px]">Resume</span>
                                {personal.resume_path ? <DocumentViewer src={personal.resume_path} fileName="Resume" variant="link" /> : '-'}
                            </div>
                            <div className="flex flex-col sm:flex-row sm:justify-between py-2 border-b border-gray-100 last:border-0">
                                <span className="text-sm text-slate-500 min-w-[150px]">Domicile Certificate</span>
                                {personal.domicile_path ? <DocumentViewer src={personal.domicile_path} fileName="Domicile Certificate" variant="link" /> : '-'}
                            </div>
                        </Section>

                        <Section title="Contact Information" icon={Phone}>
                            <InfoRow label="Mobile Number" value={applicant.mobile_no} />
                            <InfoRow label="Email Address" value={applicant.email} />
                        </Section>
                    </div>

                    <div className="space-y-6">
                        <Section title="Current Address" icon={MapPin}>
                            <InfoRow label="Address" value={address.address_line} />
                            {address.address_line2 && <InfoRow label="Line 2" value={address.address_line2} />}
                            <InfoRow label="District" value={address.district_name} />
                            <InfoRow label="Taluka" value={address.taluka_name} />
                            <InfoRow label="Pincode" value={address.pincode} />
                        </Section>

                        <Section title="Permanent Address" icon={MapPin}>
                            {address.permanent_address_same ? (
                                <p className="text-sm text-slate-500 italic py-2">Same as current address</p>
                            ) : (
                                <>
                                    <InfoRow label="Address" value={address.permanent_address_line} />
                                    {address.permanent_address_line2 && <InfoRow label="Line 2" value={address.permanent_address_line2} />}
                                    <InfoRow label="District" value={address.permanent_district_name} />
                                    <InfoRow label="Taluka" value={address.permanent_taluka_name} />
                                    <InfoRow label="Pincode" value={address.permanent_pincode} />
                                </>
                            )}
                        </Section>
                    </div>
                </div>
            )}

            {activeTab === 'education_experience' && (
                <div className="grid grid-cols-1 gap-6 animate-in fade-in slide-in-from-bottom-2">
                    <Section title="Education" icon={FileText}>
                        {education.length > 0 ? (
                            <div className="overflow-x-auto">
                                <table className="min-w-full divide-y divide-slate-200">
                                    <thead>
                                        <tr>
                                            <th className="px-3 py-2 text-left text-xs font-medium text-slate-500 uppercase text-slate-800">Level</th>
                                            <th className="px-3 py-2 text-left text-xs font-medium text-slate-500 uppercase text-slate-800 ">Degree</th>
                                            <th className="px-3 py-2 text-left text-xs font-medium text-slate-500 uppercase text-slate-800">Board/University</th>
                                            <th className="px-3 py-2 text-left text-xs font-medium text-slate-500 uppercase text-slate-800">Year</th>
                                            <th className="px-3 py-2 text-left text-xs font-medium text-slate-500 uppercase text-slate-800">Percentage</th>
                                            <th className="px-3 py-2 text-left text-xs font-medium text-slate-500 uppercase text-slate-800">Certificate</th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-slate-200">
                                        {education.map((edu, idx) => (
                                            <tr key={edu.education_id || idx}>
                                                <td className="px-3 py-2 text-sm text-slate-900">{edu.level_name}</td>
                                                <td className="px-3 py-2 text-sm text-slate-500">{edu.degree_name}</td>
                                                <td className="px-3 py-2 text-sm text-slate-500">{edu.university_board}</td>
                                                <td className="px-3 py-2 text-sm text-slate-500">{edu.passing_year}</td>
                                                <td className="px-3 py-2 text-sm text-slate-500">{edu.percentage}%</td>
                                                <td className="px-3 py-2 text-sm text-slate-500">{edu.certificate_path ? <DocumentViewer src={edu.certificate_path} fileName="Education Certificate" variant="link" /> : '-'}</td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            </div>
                        ) : (
                            <p className="text-sm text-slate-500">No education details found.</p>
                        )}
                    </Section>

                    <Section title="Experience" icon={Calendar}>
                        {experience.length > 0 ? (
                            <div className="overflow-x-auto">
                                <table className="min-w-full divide-y divide-slate-200">
                                    <thead>
                                        <tr>
                                            <th className="px-3 py-2 text-left text-xs font-medium text-slate-500 uppercase text-slate-800">Organization</th>
                                            <th className="px-3 py-2 text-left text-xs font-medium text-slate-500 uppercase text-slate-800">Designation</th>
                                            <th className="px-3 py-2 text-left text-xs font-medium text-slate-500 uppercase text-slate-800">Period</th>
                                            <th className="px-3 py-2 text-left text-xs font-medium text-slate-500 uppercase text-slate-800">Months</th>
                                            <th className="px-3 py-2 text-left text-xs font-medium text-slate-500 uppercase text-slate-800">Certificate</th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-slate-200">
                                        {experience.map((exp, idx) => (
                                            <tr key={exp.experience_id || idx}>
                                                <td className="px-3 py-2 text-sm text-slate-900">{exp.organization_name}</td>
                                                <td className="px-3 py-2 text-sm text-slate-500">{exp.designation}</td>
                                                <td className="px-3 py-2 text-sm text-slate-500">
                                                    {formatDateISTNoTime(exp.start_date)} - {exp.is_current ? 'Present' : formatDateISTNoTime(exp.end_date)}
                                                </td>
                                                <td className="px-3 py-2 text-sm text-slate-500">{exp.total_months}</td>
                                                <td className="px-3 py-2 text-sm text-slate-500">{exp.certificate_path ? <DocumentViewer src={exp.certificate_path} fileName="Experience Certificate" variant="link" /> : '-'}</td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            </div>
                        ) : (
                            <p className="text-sm text-slate-500">No experience details found.</p>
                        )}
                    </Section>
                </div>
            )}

            {activeTab === 'skills' && (
                <div className="grid grid-cols-1 gap-6 animate-in fade-in slide-in-from-bottom-2">
                    <Section title="Skills" icon={CreditCard}>
                        {skills.length > 0 ? (
                            <div className="overflow-x-auto">
                                <table className="min-w-full divide-y divide-slate-200">
                                    <thead>
                                        <tr>
                                            <th className="px-3 py-2 text-left text-xs font-medium text-slate-500 uppercase text-slate-800">Skill</th>
                                            <th className="px-3 py-2 text-left text-xs font-medium text-slate-500 uppercase text-slate-800">Notes</th>
                                            <th className="px-3 py-2 text-left text-xs font-medium text-slate-500 uppercase text-slate-800">Certificate</th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-slate-200">
                                        {skills.map((s, idx) => (
                                            <tr key={s.applicant_skill_id || idx}>
                                                <td className="px-3 py-2 text-sm text-slate-900">{s?.skill?.skill_name || '-'}</td>
                                                <td className="px-3 py-2 text-sm text-slate-500">{s?.notes || '-'}</td>
                                                <td className="px-3 py-2 text-sm text-slate-500">{s?.certificate_path ? <MediaViewer src={s.certificate_path} fileName="Skill Certificate" variant="link" /> : '-'}</td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            </div>
                        ) : (
                            <p className="text-sm text-slate-500">No skills found.</p>
                        )}
                    </Section>
                </div>
            )}

            {activeTab === 'documents' && (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 animate-in fade-in slide-in-from-bottom-2">
                    {extraDocuments.map((doc, idx) => (
                        <MediaViewer
                            key={doc.document_id || idx}
                            src={doc.file_path}
                            fileName={doc.doc_type_name || 'Document'}
                            variant="card"
                        />
                    ))}
                    {extraDocuments.length === 0 && (
                        <div className="col-span-full py-8 text-center text-slate-500">No documents uploaded.</div>
                    )}
                </div>
            )}

            {activeTab === 'applications' && (
                <div className="animate-in fade-in slide-in-from-bottom-2">
                    <DataTable
                        columns={applicationColumns}
                        data={applications}
                        isLoading={loading}
                        rowKey="application_id"
                        headerClassName="bg-slate-900 text-white"
                        pagination={{
                            pageSize: 10,
                        }}
                    />
                </div>
            )}
        </div>
    );
};

export default ApplicantView;
